plugins.source_code:
desc:Simple Mono Synth
slider1:0.3<0,1,0.01>Volume
slider2:0.5<0,1,0.01>Filter Cutoff

@init
note = -1;
vel = 0;
phase = 0;
lp0 = 0;
lp1 = 0;

@block
while (midirecv(offset, msg1, msg2, msg3)) (
  status = msg1 & 0xF0;
  status == 0x90 && msg3 > 0 ? (
    note = msg2;
    vel = msg3 / 127;
  );
  status == 0x80 || (status == 0x90 && msg3 == 0) ? (
    msg2 == note ? note = -1;
  );
);

@sample
note >= 0 ? (
  freq = 440 * 2^((note - 69) / 12);
  phase += freq / srate;
  phase >= 1 ? phase -= 1;
  osc = 2 * phase - 1;
  fc = slider2 * slider2 * 0.49;
  lp0 += fc * (osc - lp0);
  lp1 += fc * (lp0 - lp1);
  out = lp1 * vel * slider1;
) : (
  out = 0;
);
spl0 = out;
spl1 = out;
